import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { misAPI } from '../services/api';
import {
  BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';

const MISPage = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (user?.role !== 'manager') {
      navigate('/dashboard');
      return;
    }

    const fetchMISData = async () => {
      try {
        setLoading(true);
        const response = await misAPI.getStats();
        console.log("MIS DATA:", response.data);
        setData(response?.data || {});
        setError('');
      } catch (err) {
        console.error("MIS ERROR:", err);
        setError(err?.response?.data?.message || 'Failed to fetch MIS data');
      } finally {
        setLoading(false);
      }
    };

    fetchMISData();
  }, [user, navigate]);

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const handleRetry = () => {
    window.location.reload();
  };

  const COLORS = ['#FFBB28', '#6366F1', '#22C55E'];

  // ---------------- LOADING ----------------
  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-gray-100 to-gray-200">
        <p className="text-lg font-semibold text-gray-600 animate-pulse">
          Loading MIS reports...
        </p>
      </div>
    );
  }

  // ---------------- ERROR ----------------
  if (error) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-100">
        <div className="bg-red-100 border border-red-400 text-red-700 p-4 rounded mb-4 shadow">
          {error}
        </div>
        <button
          onClick={handleRetry}
          className="px-5 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition"
        >
          Retry
        </button>
      </div>
    );
  }

  // ---------------- MAIN ----------------
  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-100 to-gray-200">

      {/* HEADER */}
      <header className="bg-gradient-to-r from-blue-600 to-indigo-600 shadow-lg">
        <div className="max-w-7xl mx-auto px-6 py-5 flex justify-between items-center text-white">
          <div>
            <h1 className="text-3xl font-bold">📊 MIS Reports</h1>
            <p className="text-sm text-blue-100">
              Performance & Progress Dashboard
            </p>
          </div>

          <div className="flex gap-3">
            <button
              onClick={() => navigate('/dashboard')}
              className="px-4 py-2 bg-white/20 hover:bg-white/30 rounded-lg transition"
            >
              Back
            </button>

            <button
              onClick={handleLogout}
              className="px-4 py-2 bg-red-500 hover:bg-red-600 rounded-lg transition"
            >
              Logout
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 py-8">

        {data?.summary && (
          <>
            {/* SUMMARY */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-10">
              <StatCard title="Total Tasks" value={data.summary.totalTasks} color="blue" />
              <StatCard title="Completed" value={data.summary.completedTasks} color="green" extra={`${data.summary.completionRate}%`} />
              <StatCard title="Overdue" value={data.summary.overdueTasks} color="red" />
              <StatCard title="Upcoming" value={data.summary.upcomingTasks} color="yellow" />
            </div>

            {/* CHARTS */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-10">

              <ChartCard title="Task Status">
                <ResponsiveContainer width="100%" height={300}>
                  <PieChart>
                    <Pie
                      data={[
                        { name: 'Pending', value: data.summary.pendingTasks },
                        { name: 'In Progress', value: data.summary.inProgressTasks },
                        { name: 'Completed', value: data.summary.completedTasks },
                      ]}
                      dataKey="value"
                      outerRadius={90}
                      label
                    >
                      {COLORS.map((color, i) => (
                        <Cell key={i} fill={color} />
                      ))}
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              </ChartCard>

              <ChartCard title="Department Tasks">
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={data.departmentStats || []}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="department" />
                    <YAxis />
                    <Tooltip />
                    <Bar dataKey="total" fill="#6366F1" />
                    <Bar dataKey="completed" fill="#22C55E" />
                  </BarChart>
                </ResponsiveContainer>
              </ChartCard>

            </div>

            {/* TABLE */}
            <div className="bg-white p-6 rounded-2xl shadow-lg">
              <h2 className="text-xl font-bold mb-4">👥 Employee Performance</h2>

              {(data.employeePerformance || []).length === 0 ? (
                <p className="text-gray-500 text-center py-6">No data available</p>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full">
                    <thead className="bg-gray-100">
                      <tr>
                        <th className="p-3 text-left">Employee</th>
                        <th>Assigned</th>
                        <th>Completed</th>
                        <th>Rate</th>
                      </tr>
                    </thead>

                    <tbody>
                      {data.employeePerformance.map((emp, i) => (
                        <tr key={i} className="border-b hover:bg-gray-50 transition">
                          <td className="p-3 font-semibold">{emp.employeeName}</td>
                          <td className="text-center">{emp.totalAssigned}</td>
                          <td className="text-center text-green-600 font-semibold">
                            {emp.completed}
                          </td>
                          <td className="text-center font-semibold">
                            {emp.completionRate}%
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>

          </>
        )}

      </main>
    </div>
  );
};

// ---------------- COMPONENTS ----------------

const StatCard = ({ title, value, color, extra }) => (
  <div className="bg-white p-6 rounded-2xl shadow-lg hover:shadow-xl transition">
    <p className="text-gray-500 text-sm">{title}</p>
    <p className={`text-3xl font-bold text-${color}-600`}>
      {value || 0}
    </p>
    {extra && <p className="text-xs text-gray-400">{extra}</p>}
  </div>
);

const ChartCard = ({ title, children }) => (
  <div className="bg-white p-6 rounded-2xl shadow-lg hover:shadow-xl transition">
    <h2 className="text-lg font-semibold mb-4">{title}</h2>
    {children}
  </div>
);

export default MISPage;
